import java.io.*;
import java.util.*;
class Main{
    static class Node{int data; Node left,right; Node(int d){data=d;}};
    static Node buildTree(List<String> tok){
        if(tok.isEmpty()) return null;
        Node root=new Node(Integer.parseInt(tok.get(0)));
        Queue<Node> q=new ArrayDeque<>(); q.add(root);
        int i=1;
        while(!q.isEmpty() && i<tok.size()){
            Node cur=q.poll();
            if(i<tok.size() && !tok.get(i).equals("N")){
                cur.left=new Node(Integer.parseInt(tok.get(i)));
                q.add(cur.left);
            }
            i++;
            if(i<tok.size() && !tok.get(i).equals("N")){
                cur.right=new Node(Integer.parseInt(tok.get(i)));
                q.add(cur.right);
            }
            i++;
        }
        return root;
    }
    static void inorder(Node r, StringBuilder sb){
        if(r==null) return;
        inorder(r.left,sb);
        sb.append(r.data).append(' ');
        inorder(r.right,sb);
    }
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        int T=Integer.parseInt(br.readLine().trim());
        StringBuilder out=new StringBuilder();
        for(int t=0;t<T;++t){
            String line=br.readLine();
            while(line!=null && line.trim().isEmpty()) line=br.readLine();
            List<String> tok=new ArrayList<>();
            if(line!=null){
                StringTokenizer st=new StringTokenizer(line);
                while(st.hasMoreTokens()) tok.add(st.nextToken());
            }
            Node root=buildTree(tok);
            StringBuilder sb=new StringBuilder();
            inorder(root,sb);
            out.append(sb).append('\n');
        }
        System.out.print(out.toString());
    }
}

