import sys
from collections import deque

def build_tree(tokens):
    if not tokens:
        return None
    root = {'val': int(tokens[0]), 'left': None, 'right': None}
    q = deque([root])
    i = 1
    while q and i < len(tokens):
        cur = q.popleft()
        if i < len(tokens) and tokens[i] != 'N':
            cur['left'] = {'val': int(tokens[i]), 'left': None, 'right': None}
            q.append(cur['left'])
        i += 1
        if i < len(tokens) and tokens[i] != 'N':
            cur['right'] = {'val': int(tokens[i]), 'left': None, 'right': None}
            q.append(cur['right'])
        i += 1
    return root

def inorder(node, out):
    if not node:
        return
    inorder(node['left'], out)
    out.append(str(node['val']))
    inorder(node['right'], out)

def solve():
    data = sys.stdin.read().strip().split('\n')
    if not data:
        return
    T = int(data[0].strip())
    lines = data[1:]
    idx = 0
    out_lines = []
    for _ in range(T):
        while idx < len(lines) and lines[idx].strip() == '':
            idx += 1
        if idx >= len(lines):
            break
        tokens = lines[idx].strip().split()
        idx += 1
        root = build_tree(tokens)
        res = []
        inorder(root, res)
        out_lines.append(' '.join(res) + ' ')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

