let outputs = [];
function buildTree(tokens){
  if(tokens.length===0) return null;
  const root = {val: parseInt(tokens[0]), left:null, right:null};
  const q = [root];
  let i = 1;
  while(q.length && i < tokens.length){
    const cur = q.shift();
    if(i < tokens.length && tokens[i] !== 'N'){
      cur.left = {val: parseInt(tokens[i]), left:null, right:null};
      q.push(cur.left);
    }
    i++;
    if(i < tokens.length && tokens[i] !== 'N'){
      cur.right = {val: parseInt(tokens[i]), left:null, right:null};
      q.push(cur.right);
    }
    i++;
  }
  return root;
}
function inorder(node, arr){
  if(!node) return;
  inorder(node.left, arr);
  arr.push(node.val);
  inorder(node.right, arr);
